import React, { useState, useEffect, useRef } from 'react';
import VendorForm from './VendorForm';
import { getVendors, deleteVendor, createVendor, updateVendor } from '../services/api';

interface Vendor {
  id: number;
  name: string;
  currency: string;
  contactPerson: string;
  email: string;
  phone: string;
  website: string;
  description?: string;
}

const VendorTable: React.FC = () => {
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [activeFilter, setActiveFilter] = useState<string>('Active Vendors');
  const [loading, setLoading] = useState<boolean>(false);
  const [saving, setSaving] = useState<boolean>(false);
  const [open, setOpen] = useState<boolean>(false);
  const [editing, setEditing] = useState<Vendor | null>(null);
  const [actionAnchorEl, setActionAnchorEl] = useState<HTMLElement | null>(null);
  const [actionRow, setActionRow] = useState<Vendor | null>(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const actionMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchVendors();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        actionMenuRef.current &&
        !actionMenuRef.current.contains(event.target as Node) &&
        actionAnchorEl &&
        !actionAnchorEl.contains(event.target as Node)
      ) {
        setActionAnchorEl(null);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [actionAnchorEl]);

  const fetchVendors = async () => {
    setLoading(true);
    try {
      const response = await getVendors();
      setVendors(
        response.data.map((vendor: any) => ({
          id: vendor.id,
          name: vendor.name || '',
          currency: vendor.currency || '',
          contactPerson: vendor.contact_person || vendor.contact || '',
          email: vendor.email || '',
          phone: vendor.phone || '',
          website: vendor.website || '',
          description: vendor.description || '',
        }))
      );
    } catch (error) {
      console.error('Error fetching vendors:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleOpen = (item: Vendor | null = null) => {
    setEditing(item);
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = async (vendorData: any) => {
    setSaving(true);
    try {
      if (editing) {
        await updateVendor(editing.id, vendorData);
      } else {
        await createVendor(vendorData);
      }
      await fetchVendors();
      setOpen(false);
      setEditing(null);
    } catch (error) {
      console.error('Error saving vendor:', error);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm('Are you sure you want to delete this vendor?')) {
      try {
        await deleteVendor(id);
        fetchVendors();
      } catch (error) {
        console.error('Error deleting vendor:', error);
      }
    }
  };

  const totalPages = Math.ceil(vendors.length / pageSize);
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const paginatedData = vendors.slice(startIndex, endIndex);

  const handlePageChange = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setPageSize(Number(e.target.value));
    setCurrentPage(1);
  };

  const actionMenuStyle = actionAnchorEl
    ? {
        position: 'absolute' as const,
        top: actionAnchorEl.getBoundingClientRect().bottom + window.scrollY + 8,
        left: actionAnchorEl.getBoundingClientRect().left + window.scrollX,
      }
    : undefined;

  return (
    <div className="bg-white rounded-lg shadow-sm p-6 space-y-5">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-4">
        <div className="flex flex-col md:flex-row md:items-center gap-3 w-full md:w-auto">
          <select
            value={activeFilter}
            onChange={(e) => setActiveFilter(e.target.value)}
            className="w-full md:w-64 rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="Active Vendors">Active Vendors</option>
            <option value="Inactive Vendors">Inactive Vendors</option>
          </select>
          <button
            onClick={() => handleOpen()}
            className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
            type="button"
          >
            New Vendor
          </button>
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <button
            type="button"
            onClick={() => setActiveFilter('Active Vendors')}
            className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            Clear All Filters
          </button>
          <button
            type="button"
            className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            Select Columns
          </button>
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center items-center py-20">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      ) : (
        <>
          <div className="overflow-x-auto rounded-lg border border-slate-200 bg-white shadow-sm">
            <table className="w-full min-w-[700px] divide-y divide-slate-200">
              <thead className="bg-[#fafafa]">
                <tr>
                  <th className="w-12 px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500"></th>
                  <th className="px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
                    Name
                  </th>
                  <th className="px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
                    Currency
                  </th>
                  <th className="px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
                    Contact Person
                  </th>
                  <th className="px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
                    Email
                  </th>
                  <th className="px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
                    Phone
                  </th>
                  <th className="px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
                    Website
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-slate-200">
                {paginatedData.length > 0 ? (
                  paginatedData.map((vendor) => (
                    <tr key={vendor.id} className="hover:bg-slate-50">
                      <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900">
                        <button
                          onClick={(event) => {
                            event.stopPropagation();
                            setActionRow(vendor);
                            setActionAnchorEl(event.currentTarget);
                          }}
                          className="rounded-full border border-slate-300 bg-white p-2 text-slate-500 hover:bg-slate-50 focus:outline-none"
                          type="button"
                          aria-label="Actions"
                        >
                          <svg width="16" height="16" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                            <rect y="4" width="20" height="2" rx="1" fill="currentColor" />
                            <rect y="9" width="20" height="2" rx="1" fill="currentColor" />
                            <rect y="14" width="20" height="2" rx="1" fill="currentColor" />
                          </svg>
                        </button>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-slate-900">{vendor.name}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-slate-900">{vendor.currency}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-slate-900">{vendor.contactPerson}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-slate-900">{vendor.email}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-slate-900">{vendor.phone}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-slate-900">{vendor.website}</td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={7} className="px-6 py-4 text-center text-sm text-gray-500">
                      No vendors found
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination */}
          <div className="mt-6 flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2 text-sm text-slate-700">
          <span>Page Size:</span>
          <select
            value={pageSize}
            onChange={handlePageSizeChange}
            className="rounded-md border border-slate-300 bg-white px-3 py-1 text-sm focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>

        <div className="flex flex-wrap items-center gap-3 text-sm text-slate-600">
          <span>
            {vendors.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(endIndex, vendors.length)} of ${vendors.length}`}
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
              type="button"
            >
              ←
            </button>
            <span className="text-sm text-slate-600">Page {currentPage} of {totalPages === 0 ? 1 : totalPages}</span>
            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
              type="button"
            >
              →
            </button>
          </div>
        </div>
      </div>
        </>
      )}

      {actionAnchorEl && actionRow && (
        <div
          ref={actionMenuRef}
          className="fixed z-10 w-40 rounded-md border border-slate-200 bg-white shadow-lg"
          style={{
            position: 'absolute',
            top: actionAnchorEl.getBoundingClientRect().bottom + window.scrollY + 8,
            left: actionAnchorEl.getBoundingClientRect().left + window.scrollX,
          }}
        >
          <button
            type="button"
            onClick={() => {
              handleOpen(actionRow);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100"
          >
            Edit
          </button>
          <button
            type="button"
            onClick={() => {
              handleDelete(actionRow.id);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100"
          >
            Delete
          </button>
        </div>
      )}

      {open && (
        <VendorForm
          editing={editing}
          onSave={handleSave}
          onClose={handleClose}
          saving={saving}
        />
      )}
    </div>
  );
};

export default VendorTable;
